// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
   if (isLoading || newValue === '') {
      return;
   }

	// DFCT0011028 only fetch the Primary Assignee if it is empty.  
	// If there is a primary assignee was already set, the user needs to clear it to select a different office
	var primaryAssignee = g_form.getValue('primary_assignee');

	var ajax = new GlideAjax('ClientTaskInfo');
	if(primaryAssignee + "" == ""){
		ajax.addParam('sysparm_name', 'getTaskDefaultPrimaryAssignee');
		ajax.addParam('sysparm_task_id', g_form.getUniqueValue());
		ajax.addParam('sysparm_restricted_group', g_form.getValue('assignment_group'));
		ajax.addParam('sysparm_assigned_member', g_form.getValue('assigned_to'));
		ajax.getXML(f_returnDefaultPrimaryAssignee);		
	}

	updateOOOMsg();
	function updateOOOMsg (){
		// STRY0130635 - init was done in onload function
		var dt_ooo = x_153465_discovert.DTech_Out_of_Office;
		dt_ooo.ooo_change_user("assigned_to");

	}

	function f_returnDefaultPrimaryAssignee(response)
	{
		try{
			var defaultPrimaryAssignee = response.responseXML.documentElement.getAttribute("answer");
			if(defaultPrimaryAssignee != ''){
				g_form.setValue('primary_assignee',defaultPrimaryAssignee);
			}
		}catch(e){
			jslog(e);
		}	
	}
}
